        byte[] tmp1 = this._h.doFinal();
        this._h.reset();
        this._h.update(tmp1);
        byte[] tmp2 = this._h.doFinal();
        this._h.reset();
        this.transformBytesToLong(tmp1, tmp2);
        this.p = 0;
        long j1 = 0L;
        long j2 = 0L;
        int loopLimit = (int)Math.pow(2.0, Math.ceil(3.0 * (double)g / 4.0));
        this._hPrime.reset();
        int i = 0;
